"AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Advanced Illness (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Advanced Illness (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS AdvancedIllnessDiagnosis WHERE AdvancedIllnessDiagnosis.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(AdvancedIllnessDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(AdvancedIllnessDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) BETWEEN CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)))
),
"AIFrailLTCF.Has Criteria Indicating Frailty" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "DeviceRequest: Frailty Device" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS FrailtyDeviceOrder WHERE FrailtyDeviceOrder.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn')), '{') THEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') ELSE intervalFromBounds(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn')), '{') THEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') ELSE intervalFromBounds(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Medical equipment used" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS EquipmentUsed WHERE EquipmentUsed.patient_id = p.patient_id AND in_valueset(EquipmentUsed.resource, 'value', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.464.1003.118.12.1300') AND CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(EquipmentUsed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EquipmentUsed.resource, 'effective')), '{') THEN fhirpath_text(EquipmentUsed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EquipmentUsed.resource, 'effective'), fhirpath_text(EquipmentUsed.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) BETWEEN CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS FrailtyDiagnosis WHERE FrailtyDiagnosis.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(FrailtyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(FrailtyDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Frailty Encounter" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS FrailtyEncounter WHERE FrailtyEncounter.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(FrailtyEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(FrailtyEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Frailty Symptom" WHERE fhirpath_text(resource, 'status') IN ('preliminary', 'final', 'amended', 'corrected')) AS FrailtySymptom WHERE FrailtySymptom.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(FrailtySymptom.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtySymptom.resource, 'effective')), '{') THEN fhirpath_text(FrailtySymptom.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FrailtySymptom.resource, 'effective'), fhirpath_text(FrailtySymptom.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtySymptom.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtySymptom.resource, 'effective')), '{') THEN fhirpath_text(FrailtySymptom.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FrailtySymptom.resource, 'effective'), fhirpath_text(FrailtySymptom.resource, 'effective'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
