"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 66 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id))
),
"AIFrailLTCF.Is Age 66 to 80 with Advanced Illness and Frailty or Is Age 81 or Older with Frailty" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 66 AND 80 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)) OR EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 81 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"Glycemic Status Assessment" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Observation: HbA1c Laboratory Test" UNION SELECT patient_id, resource FROM "Observation: Glucose management indicator") AS _union WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS GlycemicStatus WHERE CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(GlycemicStatus.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(GlycemicStatus.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(GlycemicStatus.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(GlycemicStatus.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)
),
"Has No Record Of Glycemic Status Assessment" AS (
SELECT p.patient_id FROM _patients AS p WHERE NOT EXISTS (SELECT 1 FROM "Glycemic Status Assessment" AS sub WHERE sub.patient_id = p.patient_id)
),
"Most Recent Glycemic Status Date" AS (
SELECT p.patient_id, (SELECT LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(QualifyingGlycemicStatus.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(QualifyingGlycemicStatus.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) FROM "Glycemic Status Assessment" AS QualifyingGlycemicStatus WHERE QualifyingGlycemicStatus.patient_id = p.patient_id ORDER BY LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(QualifyingGlycemicStatus.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(QualifyingGlycemicStatus.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) DESC NULLS FIRST, json_extract_string(QualifyingGlycemicStatus.resource, '$.id') ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Lowest Glycemic Status Assessment Reading on Most Recent Day" AS (
SELECT p.patient_id, json_extract_string((SELECT json_object('QualifyingGlycemicStatusValue', parse_quantity(fhirpath_text(QualifyingGlycemicStatus.resource, 'value')), 'QualifyingGlycemicStatus', QualifyingGlycemicStatus.resource) FROM "Glycemic Status Assessment" AS QualifyingGlycemicStatus WHERE cqlSameAsP(CAST(COALESCE(CAST(fhirpath_date(QualifyingGlycemicStatus.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(QualifyingGlycemicStatus.resource, 'effectivePeriod'))) AS VARCHAR), CAST((SELECT sub.value FROM "Most Recent Glycemic Status Date" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), 'day') AND QualifyingGlycemicStatus.patient_id = p.patient_id ORDER BY parse_quantity(fhirpath_text(QualifyingGlycemicStatus.resource, 'value')) ASC NULLS LAST, json_extract_string(QualifyingGlycemicStatus.resource, '$.id') ASC NULLS LAST LIMIT 1), '$.QualifyingGlycemicStatus') AS resource FROM _patients AS p
),
"Has Most Recent Elevated Glycemic Status Assessment" AS (
SELECT p.patient_id FROM _patients AS p WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text((SELECT sub.resource FROM "Lowest Glycemic Status Assessment Reading on Most Recent Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'value')), '{') THEN json_extract_string(fhirpath_text((SELECT sub.resource FROM "Lowest Glycemic Status Assessment Reading on Most Recent Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'value'), '$.value') ELSE fhirpath_text((SELECT sub.resource FROM "Lowest Glycemic Status Assessment Reading on Most Recent Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'value') END AS DOUBLE) > 9.0
),
"Has Most Recent Glycemic Status Assessment Without Result" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Lowest Glycemic Status Assessment Reading on Most Recent Day" AS j1 ON j1.patient_id = p.patient_id WHERE j1.resource IS NOT NULL AND fhirpath_text((SELECT sub.resource FROM "Lowest Glycemic Status Assessment Reading on Most Recent Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1), 'value') IS NULL
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Most Recent Glycemic Status Assessment Without Result" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Most Recent Elevated Glycemic Status Assessment" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has No Record Of Glycemic Status Assessment" AS sub WHERE sub.patient_id = p.patient_id)
),
"Qualifying Encounters" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Annual Wellness Visit" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Established Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services Initial Office Visit, 18 and Up" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Nutrition Services" UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.ama-assn.org/go/cpt'' and code=''97802'').exists()')) UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.ama-assn.org/go/cpt'' and code=''97803'').exists()')) UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.ama-assn.org/go/cpt'' and code=''97804'').exists()')) UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.cms.gov/Medicare/Coding/HCPCSReleaseCodeSets'' and code=''G0270'').exists()')) UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.cms.gov/Medicare/Coding/HCPCSReleaseCodeSets'' and code=''G0271'').exists()')) UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ValidEncounters WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ValidEncounters.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ValidEncounters.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 18 AND 75 AND EXISTS (SELECT 1 FROM "Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Diabetes (qicore-condition-encounter-diagnosis)" WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS DiabetesDiagnosis WHERE DiabetesDiagnosis.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(DiabetesDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), fhirpath_text(DiabetesDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(DiabetesDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(DiabetesDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), fhirpath_text(DiabetesDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(DiabetesDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(DiabetesDiagnosis.resource, 'onsetDateTime'), fhirpath_text(DiabetesDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(DiabetesDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
